sql:
SELECT j.job_id, jm.metric_name
FROM jobs j
JOIN job_metrics jm ON j.job_id = jm.job_id;

SELECT job_id, job_type, job_duration
FROM jobs
WHERE job_duration < 60 AND job_type IN ('evaluate', 'train');

external_knowledge:
- 'took more than five minutes' refers to a job duration greater than 300 seconds;
- 'accuracy metric above 95%' means the average metric value for 'accuracy' should be higher than 0.95;
- The jobs under consideration must belong to the 'AI Team'.

sql:
SELECT version_number, version_description
FROM job_versions
WHERE job_id = '1';

SELECT u.user_name, j.job_id, j.job_type
FROM jobs j
INNER JOIN users u ON j.user_id = u.user_id;

SELECT DISTINCT job_id
FROM job_comments
WHERE is_important = 1;
